import{_ as t,o as a,c as o,ag as n}from"./chunks/framework.DmWB24NN.js";const g=JSON.parse('{"title":"CHAPTER 6: COMBAT SKILLS","description":"","frontmatter":{},"headers":[],"relativePath":"Book I - Core Rules/B01 - Chapter 06_ Combat Skills.md","filePath":"Book I - Core Rules/B01 - Chapter 06_ Combat Skills.md"}'),r={name:"Book I - Core Rules/B01 - Chapter 06_ Combat Skills.md"};function s(i,e,l,d,h,p){return a(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="chapter-6-combat-skills" tabindex="-1"><strong>CHAPTER 6: COMBAT SKILLS</strong> <a class="header-anchor" href="#chapter-6-combat-skills" aria-label="Permalink to &quot;**CHAPTER 6: COMBAT SKILLS**&quot;">​</a></h1><p>Combat skills determine which weapons a character can use effectively and how they use them. They are purchased with Skill Points — a resource allocated at character creation and expanded as a character advances.</p><hr><h2 id="learning-skills" tabindex="-1"><strong>Learning Skills</strong> <a class="header-anchor" href="#learning-skills" aria-label="Permalink to &quot;**Learning Skills**&quot;">​</a></h2><p>Characters receive skill points at 1st level and gain additional points as they advance. Skill points not spent at character creation are lost — they represent training completed before play, not banked resources. Points earned at later levels may be saved, but can only be spent during level advancement. The GM may require that a character find a trainer to acquire particularly difficult or specialized skills.</p><h3 id="table-6-1-skill-points-by-class-group" tabindex="-1"><strong>Table 6.1: Skill Points by Class Group</strong> <a class="header-anchor" href="#table-6-1-skill-points-by-class-group" aria-label="Permalink to &quot;**Table 6.1: Skill Points by Class Group**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Class Group</th><th>SPs at 1st Level</th><th>Additional SPs</th></tr></thead><tbody><tr><td>Warrior</td><td>7</td><td>+2 per 3 levels</td></tr><tr><td>Priest or Rogue</td><td>5</td><td>+2 per 4 levels</td></tr><tr><td>Wizard</td><td>6</td><td>+2 per 3 levels</td></tr></tbody></table><p><strong>Multiclass characters</strong> use the most favorable row and do not add points from multiple classes. A Fighter/Mage uses the Warrior row.</p><p><strong>Intelligence bonus.</strong> The bonus languages score from Table 1.4 may be added in whole or in part to skill points at 1st level, at the GM&#39;s discretion.</p><p><strong>Starting trade or knowledge.</strong> Every character receives one free Trade or Knowledge skill at character creation, representing their life before adventuring. This skill is chosen freely and does not cost a skill point.</p><p><strong>Minimum Skill Spend.</strong> At character creation, Wizards need to spend at least 4 SP in Non-Combat Skills. Fighters need to spend at least 3 SP in Combat Skills. Rogues and Priests have no minimum spend, except that no character can start the game with all their SP allocated in only one group (Combat Skills or Non-Combat Skills).</p><hr><h2 id="combat-skill-points" tabindex="-1"><strong>Combat Skill Points</strong> <a class="header-anchor" href="#combat-skill-points" aria-label="Permalink to &quot;**Combat Skill Points**&quot;">​</a></h2><p>Any character can purchase Combat Skill Points at 1st level. These must be purchased from the permitted weapon list or purchased outside at a higher cost.</p><p>Skill points not spent at character creation are lost — they represent training completed before play, not banked resources. Points earned at later levels may be saved, but can only be spent during level advancement. The GM may require that a character find a trainer to acquire particularly difficult or specialized skills.</p><p>A character is considered unskilled with any weapon or combat method for which they have not spent a SP. The consequences of fighting unskilled are detailed below.</p><p>Once a combat skill has been chosen, the choice is permanent.</p><hr><h2 id="unskilled-penalties" tabindex="-1"><strong>Unskilled Penalties</strong> <a class="header-anchor" href="#unskilled-penalties" aria-label="Permalink to &quot;**Unskilled Penalties**&quot;">​</a></h2><p>A character who fights with a weapon they have no skill in — no individual skill, no relevant group skill, no applicable type skill — suffers a penalty to their attack rolls. The penalty varies by class group.</p><table tabindex="0"><thead><tr><th>Class Group</th><th>Unskilled Penalty</th><th>Related Weapon Penalty</th></tr></thead><tbody><tr><td>Warrior</td><td>−2</td><td>−1</td></tr><tr><td>Priest or Rogue</td><td>−3</td><td>−2</td></tr><tr><td>Wizard</td><td>−5</td><td>−3</td></tr></tbody></table><p>The <strong>unskilled penalty</strong> applies when the character has no skill with the weapon and no skill with any weapon in its group. The <strong>related weapon penalty</strong> applies when the character is unskilled with the specific weapon but skilled with another weapon in the same group — for example, a Mage skilled with a knife who picks up a dagger.</p><h2 id="training-outside-the-permitted-list" tabindex="-1"><strong>Training Outside the Permitted List</strong> <a class="header-anchor" href="#training-outside-the-permitted-list" aria-label="Permalink to &quot;**Training Outside the Permitted List**&quot;">​</a></h2><p>By default, a character can’t use weapons outside their permitted weapon list, as listed in Chapter 3: Classes. However, by spending twice the normal Skill Points, they can.</p><p>So, for example, if a Mage decides to have training in Greatsword, it will cost 2 SP instead of 1. Normal requisites for minimum Strength or any other attribute still apply.</p><p>It’s possible to purchase individual weapon training outside the permitted list, not weaponry groups or types. So, the Mage can purchase training in Greatsword by spending 2 SP, but not Swords (group) or Slashing Weapons (type). As an optional rule, the game table might decide to allow the purchase of weaponry groups and/or types. In this case, the necessary SP would also be twice the normal number.</p><hr><h2 id="weaponry-skills" tabindex="-1"><strong>Weaponry Skills</strong> <a class="header-anchor" href="#weaponry-skills" aria-label="Permalink to &quot;**Weaponry Skills**&quot;">​</a></h2><h3 id="single-weapon" tabindex="-1"><strong>Single Weapon</strong> <a class="header-anchor" href="#single-weapon" aria-label="Permalink to &quot;**Single Weapon**&quot;">​</a></h3><p><strong>Cost: 1 SP.</strong> The character becomes skilled with one specific weapon. This eliminates the unskilled penalty for that weapon and reduces the related weapon penalty when using other weapons in the same group.</p><h3 id="weaponry-group" tabindex="-1"><strong>Weaponry Group</strong> <a class="header-anchor" href="#weaponry-group" aria-label="Permalink to &quot;**Weaponry Group**&quot;">​</a></h3><p><strong>Cost: 2 SPs.</strong> A weaponry group consists of weapons of similar design — swords, axes, pole arms, and so on. Spending 2 SPs grants skill with every weapon in the group that the character&#39;s class permits. When the GM introduces new weapons, they should determine which group they belong to.</p><p>The arquebus, blowgun, and quarterstaff belong to no group and must be learned individually.</p><h3 id="table-6-2-weaponry-groups" tabindex="-1"><strong>Table 6.2: Weaponry Groups</strong> <a class="header-anchor" href="#table-6-2-weaponry-groups" aria-label="Permalink to &quot;**Table 6.2: Weaponry Groups**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Group</th><th>Weapons</th></tr></thead><tbody><tr><td>Axe</td><td>Battle axe, hand axe, throwing axe, pole axe (all)</td></tr><tr><td>Bow</td><td>Bow (all)</td></tr><tr><td>Cavalry</td><td>Horseman&#39;s flail, horseman&#39;s mace, horseman&#39;s pick</td></tr><tr><td>Club</td><td>Club, morning star, war hammer</td></tr><tr><td>Crossbow</td><td>Crossbow (all)</td></tr><tr><td>Infantry</td><td>Footman&#39;s flail, footman&#39;s mace, footman&#39;s pick</td></tr><tr><td>Lance</td><td>Lance (all)</td></tr><tr><td>Long Blade</td><td>Bastard sword, long sword, scimitar, two-handed sword</td></tr><tr><td>Medium Blade</td><td>Broad sword, cutlass, khopesh</td></tr><tr><td>Short Blade</td><td>Dagger, dirk, knife, sickle, short sword</td></tr><tr><td>Pole Arm</td><td>Pole arm (all, including pole axes)</td></tr><tr><td>Release Action</td><td>Lasso, net, scourge, sling, staff sling, whip</td></tr><tr><td>Spear</td><td>Harpoon, javelin, spear, trident</td></tr></tbody></table><h3 id="weaponry-by-type" tabindex="-1"><strong>Weaponry by Type</strong> <a class="header-anchor" href="#weaponry-by-type" aria-label="Permalink to &quot;**Weaponry by Type**&quot;">​</a></h3><p><strong>Cost: 3 SPs.</strong> Weaponry types cover the broadest range. They group weapons by the kind of damage they deal: Slashing (S), Bludgeoning (B), or Piercing (P). Spending 3 SPs grants skill with every melee or hurled weapon of that type that the character&#39;s class permits.</p><p>Weapons that deal multiple damage types are included in each relevant type. A halberd that deals both slashing and piercing damage falls under both.</p><p>Non-lethal weaponry, ranged weapons, and the arquebus and blowgun are excluded from type skills.</p><hr><h2 id="ambidexterity" tabindex="-1"><strong>Ambidexterity</strong> <a class="header-anchor" href="#ambidexterity" aria-label="Permalink to &quot;**Ambidexterity**&quot;">​</a></h2><p><strong>Cost: 1 SP.</strong> Available to all classes. Only Warriors and Rogues may use ambidexterity to fight with a weapon in each hand.</p><p>An ambidextrous character suffers no penalty when using their non-dominant hand for any action. In combat, this reduces the attack penalty to the non-dominant hand by 2 when fighting with two weapons. This reduction stacks with the character&#39;s Dexterity missile attack modifier. Ambidexterity is not a combat method and does not count against method limits.</p><hr><h2 id="combat-methods" tabindex="-1"><strong>Combat Methods</strong> <a class="header-anchor" href="#combat-methods" aria-label="Permalink to &quot;**Combat Methods**&quot;">​</a></h2><p>Beyond weaponry skills, characters may invest SPs in combat methods — specialized fighting disciplines that provide additional benefits when used with appropriate weapons.</p><p><strong>Single-class Fighters</strong> may become skilled in any or all methods, with one restriction: only one melee method may be chosen at 1st level. All other classes and all multiclass combinations are limited to one combat method, ever. Single-class Wizards and Sorcerers may only choose from ranged weaponry and unarmed methods.</p><p>A method&#39;s bonuses apply only when the character is both skilled with the weapon being used and meets the method&#39;s specific conditions. A character skilled in the Single-Weapon Method but using an unskilled weapon gains no method benefit.</p><hr><h3 id="melee-methods" tabindex="-1"><strong>Melee Methods</strong> <a class="header-anchor" href="#melee-methods" aria-label="Permalink to &quot;**Melee Methods**&quot;">​</a></h3><h4 id="single-weapon-method" tabindex="-1"><strong>Single-Weapon Method</strong> <a class="header-anchor" href="#single-weapon-method" aria-label="Permalink to &quot;**Single-Weapon Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Fighting with a single weapon in the dominant hand, nothing held in the other. No shield, no off-hand weapon — small items may be held passively (a potion, a torch) but not used offensively. Grants <strong>+1 to AC</strong>.</p><p><strong>Specialization (1 additional SP):</strong> Increases the AC bonus to <strong>+2</strong>.</p><h4 id="two-handed-method" tabindex="-1"><strong>Two-Handed Method</strong> <a class="header-anchor" href="#two-handed-method" aria-label="Permalink to &quot;**Two-Handed Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Fighting with a weapon that requires or permits the use of both hands. For weapons that can be used one- or two-handed, the bonus applies only when both hands are in use. Reduces the weapon&#39;s combat speed by 3 (minimum 0).</p><h4 id="weapon-shield-method" tabindex="-1"><strong>Weapon-Shield Method</strong> <a class="header-anchor" href="#weapon-shield-method" aria-label="Permalink to &quot;**Weapon-Shield Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Fighting with a shield in one hand and a weapon in the other. Used defensively, grants <strong>+1 to AC</strong>. Used offensively, allows a shield bash in place of a standard attack or as a secondary weapon attack, subject to non-dominant hand penalties.</p><p><strong>Specialization (1 additional SP):</strong> Defensively, increases the AC bonus to <strong>+2</strong>. Offensively, reduces the non-dominant hand attack penalty by 2 or eliminates it entirely if the character is also ambidextrous.</p><p><strong>Shield Bash.</strong> A normal attack using the shield as a weapon. Damage by shield size: buckler or light shield 1d3, medium shield 1d4, large shield 1d6. Spiked shields deal Piercing damage; standard shields deal Bludgeoning. Strength modifiers apply to the attack roll and damage. Magical shields provide no enchantment bonus to shield bash attacks. A character who makes a shield bash in a round loses their shield&#39;s AC bonus for that round.</p><h4 id="dual-weapon-method" tabindex="-1"><strong>Dual-Weapon Method</strong> <a class="header-anchor" href="#dual-weapon-method" aria-label="Permalink to &quot;**Dual-Weapon Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> An advanced form of two-weapon fighting that allows any combination of two one-handed weapons. Reduces the attack penalty to both the dominant and non-dominant hand by 2. Combined with Ambidexterity, this eliminates all penalties to two-weapon attacks.</p><p>Rangers who take the Dual-Weapon Method may use any combination of one-handed weapons but gain the penalty reduction only when wearing armor that would otherwise deny their class two-weapon fighting bonus.</p><hr><h3 id="ranged-methods" tabindex="-1"><strong>Ranged Methods</strong> <a class="header-anchor" href="#ranged-methods" aria-label="Permalink to &quot;**Ranged Methods**&quot;">​</a></h3><p>Each ranged method applies to a single weapon chosen at the time of purchase. The character must already be skilled with that weapon individually before selecting a method for it.</p><h4 id="missile-weapon-method" tabindex="-1"><strong>Missile-Weapon Method</strong> <a class="header-anchor" href="#missile-weapon-method" aria-label="Permalink to &quot;**Missile-Weapon Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Open to all classes, including Wizards using a sling. Applies to any single missile weapon requiring ammunition, excluding the arquebus.</p><p>Benefits: The character may move up to half their movement rate and still make their full attack rate. If they do not move during the round, they gain <strong>+1 to AC</strong> and <strong>+2 to attack rolls</strong> when making a called shot with the chosen weapon.</p><p>A Fighter who has also specialized in the chosen weapon and does move while firing gains +2 to attack rolls within point-blank range.</p><p>A mounted character who selects a bow or crossbow method reduces mounted firing penalties by 2 (minimum 0). If the chosen weapon is not a bow or crossbow, the character gains the ability to fire while riding at all.</p><p>Only single-class Fighters may select both Missile-Weapon Method and Hurled-Weapon Method. All others may choose one.</p><h4 id="hurled-weapon-method" tabindex="-1"><strong>Hurled-Weapon Method</strong> <a class="header-anchor" href="#hurled-weapon-method" aria-label="Permalink to &quot;**Hurled-Weapon Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Applies to any single hurled weapon the character is already skilled with, including daggers and darts for Wizards and Sorcerers.</p><p>Benefits: The character may move up to half their movement rate and make their full attack rate. If they do not move, they gain <strong>+1 to AC</strong> and <strong>+2 to attack rolls</strong> on called shots with the chosen weapon. The character also gains the ability to hurl the chosen weapon while mounted.</p><hr><h3 id="unarmed-methods" tabindex="-1"><strong>Unarmed Methods</strong> <a class="header-anchor" href="#unarmed-methods" aria-label="Permalink to &quot;**Unarmed Methods**&quot;">​</a></h3><h4 id="brawling-attack-method" tabindex="-1"><strong>Brawling-Attack Method</strong> <a class="header-anchor" href="#brawling-attack-method" aria-label="Permalink to &quot;**Brawling-Attack Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Grants <strong>+1 to attack rolls</strong> and <strong>+1 to damage</strong> while brawling. A skilled brawler may choose the next highest or lowest result on the brawling maneuver table. With both hands empty, the character may make one additional brawling attack per round.</p><h4 id="wrestling-attack-method" tabindex="-1"><strong>Wrestling-Attack Method</strong> <a class="header-anchor" href="#wrestling-attack-method" aria-label="Permalink to &quot;**Wrestling-Attack Method**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Grants <strong>+1 to attack rolls</strong> and <strong>+1 to damage</strong> while wrestling. A skilled wrestler may choose the next highest or lowest result on the wrestling maneuver table and gains <strong>+2 to Strength checks</strong> made to maintain a hold.</p><p>Only single-class Fighters may select both brawling and wrestling. All others may choose one.</p><p><strong>Unarmed Specialization (Fighter only).</strong> A single-class Fighter may spend up to 4 SPs on one or both unarmed methods. Each additional SP beyond the first increases all applicable bonuses by 1 and expands the range of maneuver results the character may choose by two (one higher, one lower). At maximum investment, a single method provides a pool of 9 possible maneuver results to select from.</p><hr><h3 id="special-methods" tabindex="-1"><strong>Special Methods</strong> <a class="header-anchor" href="#special-methods" aria-label="Permalink to &quot;**Special Methods**&quot;">​</a></h3><h4 id="messalyan-fighting-style" tabindex="-1"><strong>Messalyan Fighting Style</strong> <a class="header-anchor" href="#messalyan-fighting-style" aria-label="Permalink to &quot;**Messalyan Fighting Style**&quot;">​</a></h4><p><strong>Cost: 1 SP.</strong> Grants <strong>+2 to attack rolls</strong> and <strong>+2 to AC</strong> while fighting with a spear and no shield. These bonuses cover both melee and ranged attacks. For a Messalyan warrior, spears have Speed 4 instead of 6. The character must have a background growing up in Messalya or being taught by a Messalyan warrior.</p><hr><h2 id="weaponry-specialization" tabindex="-1"><strong>Weaponry Specialization</strong> <a class="header-anchor" href="#weaponry-specialization" aria-label="Permalink to &quot;**Weaponry Specialization**&quot;">​</a></h2><p>Specialization represents total commitment to a single weapon — years of focused practice that produce capabilities unavailable to any other class or through any other means.</p><p><strong>Available to:</strong> Single-class Fighters and Champions only. Paladins, Rangers, and all multiclass combinations cannot specialize through SP investment. Champions receive one free specialization at character creation as a class feature (Chapter 3); that specialization follows all rules below.</p><p>A Fighter may specialize in any weapon they are already skilled with. Specializing in a melee weapon costs 1 additional SP beyond the skill cost. Specializing in a bow or crossbow costs 2 additional SPs beyond the skill cost.</p><p>A Fighter may specialize in only one weapon at 1st level. Additional specializations become available as SPs are earned.</p><h3 id="specialization-benefits" tabindex="-1"><strong>Specialization Benefits</strong> <a class="header-anchor" href="#specialization-benefits" aria-label="Permalink to &quot;**Specialization Benefits**&quot;">​</a></h3><p><strong>Melee weapon:</strong> +1 to attack rolls, +2 to damage.</p><p><strong>Bow or crossbow:</strong> +2 to attack rolls when firing within point-blank range (bow: 6–30 feet; crossbow: 6–60 feet). The specialized character may fire before initiative is rolled, provided the weapon was knocked and trained on a visible target at the end of the previous round.</p><p><strong>Extra attacks:</strong> Specialization also grants additional attacks per round as the character advances. See Table 6.3.</p><h3 id="table-6-3-fighter-specialization-attack-rate" tabindex="-1"><strong>Table 6.3: Fighter Specialization Attack Rate</strong> <a class="header-anchor" href="#table-6-3-fighter-specialization-attack-rate" aria-label="Permalink to &quot;**Table 6.3: Fighter Specialization Attack Rate**&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Fighter Level</th><th>Melee Weapon</th><th>Light Crossbow</th><th>Heavy Crossbow</th><th>Thrown Dagger</th><th>Thrown Dart</th><th>Other Missile</th></tr></thead><tbody><tr><td>1–5</td><td>1/round</td><td>1/round</td><td>1/2 rounds</td><td>2/round</td><td>3/round</td><td>1/round</td></tr><tr><td>6–12</td><td>3/2 rounds</td><td>1/round</td><td>1/2 rounds</td><td>3/round</td><td>4/round</td><td>3/2 rounds</td></tr><tr><td>13+</td><td>5/2 rounds</td><td>3/2 rounds</td><td>1/round</td><td>5/round</td><td>6/round</td><td>5/2 rounds</td></tr></tbody></table><p><em>Attack rates expressed as attacks/rounds. 3/2 means three attacks every two rounds.</em></p><hr><h2 id="class-specific-notes" tabindex="-1"><strong>Class-Specific Notes</strong> <a class="header-anchor" href="#class-specific-notes" aria-label="Permalink to &quot;**Class-Specific Notes**&quot;">​</a></h2><p><strong>Champion.</strong> Champions receive one free weapon specialization at character creation, representing the focused training their Code demands. This does not cost a SP and does not count against the 1st-level limit on melee methods. All other SP expenditures for Champions follow Warrior group rules.</p><p><strong>Sorcerer.</strong> Follows Wizard group rules for SPs and method restrictions. May select one ranged or unarmed method only.</p><p><strong>Ranger — Scout Path.</strong> Rangers who take the Scout path at 8th level receive the Master Archer bonuses as a class feature, not through method investment. If a Scout has also purchased the Missile-Weapon Method, the bonuses stack only where the rules explicitly permit stacking — the attack bonus from Master Archer and the called-shot bonus from the method are separate conditions, and both apply when conditions are met.</p><p><strong>Ranger — Dual-Weapon Fighting.</strong> Rangers receive two-weapon fighting as a class feature. This does not require SP investment. If a Ranger also purchases the Dual-Weapon Method, the method&#39;s penalty reduction applies on top of the class feature, subject to the Ranger&#39;s armor restriction.</p>',105)])])}const u=t(r,[["render",s]]);export{g as __pageData,u as default};
